SELECT s.security_id, s.symbol, s.name, s.market_cap, s.exchange
FROM securities s
WHERE s.market_cap = (SELECT MAX(market_cap) FROM securities);

SELECT AVG(se.market_cap) AS average_market_cap
FROM securities se
WHERE se.status = 'active' AND se.market_cap > 0;

SELECT AVG(se.market_cap) AS average_market_cap
FROM securities se
WHERE se.exchange = 'NASDAQ';
